"""
K7 XDR Seed Data — 30 incidents, 50 devices, 200 alerts
All Indian enterprise: names, cities, hostnames, IST timestamps
"""
from datetime import datetime, timedelta
import random
import hashlib

# ── In-memory data store ──
_STORE = {"incidents": [], "devices": [], "alerts": []}

def get_data_store():
    return _STORE

NOW = datetime(2026, 2, 24, 14, 30, 0)

def ts(days=0, hours=0, mins=0):
    return (NOW - timedelta(days=days, hours=hours, minutes=mins)).isoformat() + "+05:30"

def seed_all_data(use_firestore=False):
    """Seed all data. Works with or without Firestore."""
    _STORE["devices"] = _build_devices()
    _STORE["incidents"] = _build_incidents()
    _STORE["alerts"] = _build_alerts()
    
    if use_firestore:
        try:
            from firebase_config import get_db
            db = get_db()
            if db:
                _seed_firestore(db)
        except Exception as e:
            print(f"Firestore seed skipped: {e}")
    
    print(f"✅ Seeded: {len(_STORE['incidents'])} incidents, {len(_STORE['devices'])} devices, {len(_STORE['alerts'])} alerts")

def _seed_firestore(db):
    """Write seed data to Firestore collections"""
    # Check if already seeded
    existing = db.collection("incidents").limit(1).get()
    if len(list(existing)) > 0:
        print("   Firestore already seeded, skipping")
        return
    for doc in _STORE["incidents"]:
        db.collection("incidents").document(doc["id"]).set(doc)
    for doc in _STORE["devices"]:
        db.collection("devices").document(doc["id"]).set(doc)
    batch_size = 0
    batch = db.batch()
    for doc in _STORE["alerts"]:
        ref = db.collection("alerts").document(doc["id"])
        batch.set(ref, doc)
        batch_size += 1
        if batch_size >= 400:
            batch.commit()
            batch = db.batch()
            batch_size = 0
    if batch_size > 0:
        batch.commit()
    print("   ✅ Firestore seeded")

