_ALERT_TEMPLATES = [
    ("Malware signature detected","endpoint","high","T1204"),
    ("Suspicious outbound connection","network","high","T1071.001"),
    ("Failed login attempt","identity","medium","T1110"),
    ("Phishing email blocked","email","medium","T1566"),
    ("PowerShell encoded command","endpoint","high","T1059.001"),
    ("Registry modification","endpoint","medium","T1547.001"),
    ("USB device connected","endpoint","low","T1091"),
    ("DNS query to known bad domain","network","high","T1071.004"),
    ("Service installation","endpoint","medium","T1543.003"),
    ("File encryption pattern","endpoint","critical","T1486"),
    ("LSASS access attempt","endpoint","critical","T1003.001"),
    ("Large outbound transfer","network","high","T1041"),
    ("Brute force detected","identity","medium","T1110.001"),
    ("Scheduled task created","endpoint","medium","T1053.005"),
    ("WMI remote execution","endpoint","medium","T1047"),
    ("Certificate anomaly","network","low","T1553"),
    ("Proxy bypass attempt","network","low","T1090"),
    ("Privilege escalation attempt","endpoint","high","T1068"),
    ("Shadow copy deletion","endpoint","high","T1490"),
    ("Lateral movement via SMB","network","high","T1021.002"),
]

_DEVICE_IDS = [f"DEV-{str(i).zfill(3)}" for i in range(1, 51)]
_INCIDENT_IDS = [f"INC-{str(i).zfill(4)}" for i in range(1, 31)]

def _build_alerts():
    alerts = []
    random.seed(42)  # Reproducible
    for i in range(200):
        tpl = _ALERT_TEMPLATES[i % len(_ALERT_TEMPLATES)]
        alert_name, source, severity, mitre = tpl
        device_id = _DEVICE_IDS[i % 50]
        # First 120 correlated to incidents
        correlated = i < 120
        incident_id = _INCIDENT_IDS[i % 30] if correlated else None
        status = "correlated" if correlated else random.choice(["new", "new", "suppressed"])
        
        alerts.append({
            "id": f"ALR-{str(i+1).zfill(5)}",
            "timestamp": ts(random.randint(0, 6), random.randint(0, 23), random.randint(0, 59)),
            "source": source,
            "alertName": alert_name,
            "severity": severity,
            "mitreTechnique": mitre,
            "deviceId": device_id,
            "description": f"{alert_name} on {device_id}",
            "correlatedIncidentId": incident_id,
            "status": status,
        })
    return alerts